 16→    /// <summary>
 17→    /// Resolves Service Tree node parent group info using the flattened hierarchy table and a Git-backed catalog.
 18→    /// </summary>
 19→    public sealed class ServiceTreeParentResolver : IServiceTreeParentResolver
 20→    {
 21→        private static readonly ParentServiceGroupInfo UnknownParent = new ParentServiceGroupInfo(string.Empty, string.Empty, string.Empty);
 22→
 23→        private readonly IServiceTreeNodeLookup nodeLookup;
 24→        private readonly IServiceTreeParentGroupCatalog catalog;
 25→        private readonly ILogger<ServiceTreeParentResolver> logger;
 26→        private readonly ConcurrentDictionary<string, ParentServiceGroupInfo> cache =
 27→            new ConcurrentDictionary<string, ParentServiceGroupInfo>(StringComparer.OrdinalIgnoreCase);
 28→
 29→        /// <summary>
 30→        /// Initializes a new instance of the <see cref="ServiceTreeParentResolver"/> class.
 31→        /// </summary>
 32→        /// <param name="nodeLookup">Service Tree node lookup.</param>
 33→        /// <param name="catalog">Parent group catalog.</param>
 34→        /// <param name="logger">Logger instance.</param>
 35→        public ServiceTreeParentResolver(
 36→            IServiceTreeNodeLookup nodeLookup,
 37→            IServiceTreeParentGroupCatalog catalog,
 38→            ILogger<ServiceTreeParentResolver> logger)
 39→        {
 40→            this.nodeLookup = nodeLookup ?? throw new ArgumentNullException(nameof(nodeLookup));
 41→            this.catalog = catalog ?? throw new ArgumentNullException(nameof(catalog));
 42→            this.logger = logger ?? throw new ArgumentNullException(nameof(logger));
 43→        }
 44→
 45→        /// <inheritdoc/>
 46→        public async Task<IReadOnlyDictionary<string, ParentServiceGroupInfo>> ResolveParentsAsync(
 47→            IEnumerable<string> serviceTreeIds,
 48→            CancellationToken cancellationToken)
 49→        {
 50→            var results = new ConcurrentDictionary<string, ParentServiceGroupInfo>(StringComparer.OrdinalIgnoreCase);
 51→            var uniqueIds = (serviceTreeIds ?? Enumerable.Empty<string>())
 52→                .Where(id => !string.IsNullOrWhiteSpace(id))
 53→                .Select(id => id.Trim())
 54→                .Distinct(StringComparer.OrdinalIgnoreCase)
 55→                .ToList();
 56→
 57→            if (uniqueIds.Count == 0)
 58→            {
 59→                return results;
 60→            }
 61→
 62→            var snapshot = await this.catalog.GetSnapshotAsync();
 63→            var idsToQuery = new List<string>();
 64→
 65→            foreach (var id in uniqueIds)
 66→            {
 67→                if (this.cache.TryGetValue(id, out var cached))
 68→                {
 69→                    results[id] = cached;
 70→                    continue;
 71→                }
 72→
 73→                if (snapshot.ParentsById.TryGetValue(id, out var directMatch))
 74→                {
 75→                    this.cache[id] = directMatch;
 76→                    results[id] = directMatch;
 77→                    continue;
 78→                }
 79→
 80→                idsToQuery.Add(id);
 81→            }
 82→
 83→            if (idsToQuery.Count > 0)
 84→            {
 85→                // Use the flattened hierarchy table — one query, no traversal needed.
 86→                var hierarchyResults = await this.nodeLookup
 87→                    .GetHierarchyNodesByServiceIdsAsync(idsToQuery, cancellationToken)
 88→                    .ConfigureAwait(false);
 89→
 90→                this.logger.LogInformation(
 91→                    "ServiceTreeParentResolver: Queried {QueryCount} IDs, got {ResultCount} hierarchy results.",
 92→                    idsToQuery.Count,
 93→                    hierarchyResults.Count);
 94→
 95→                foreach (var id in idsToQuery)
 96→                {
 97→                    if (hierarchyResults.TryGetValue(id, out var hierarchyNode))
 98→                    {
 99→                        var parent = this.MatchFromHierarchyNode(hierarchyNode, snapshot);
100→                        if (parent != null)
101→                        {
102→                            this.logger.LogInformation(
103→                                "ServiceTreeParentResolver: Resolved {Id} → ServiceGroupId={ServiceGroupId}, ServiceGroupName={ServiceGroupName}, Product={Product}.",
104→                                id,
105→                                parent.ServiceGroupId,
106→                                parent.ServiceGroupName,
107→                                parent.Product);
108→                            this.cache[id] = parent;
109→                            results[id] = parent;
110→                            continue;
111→                        }
112→
113→                        this.logger.LogWarning(
114→                            "ServiceTreeParentResolver: Hierarchy returned node for {Id} but no ServiceGroupId found.",
115→                            id);
116→                    }
117→                    else
118→                    {
119→                        this.logger.LogWarning(
120→                            "ServiceTreeParentResolver: No hierarchy result for {Id}.",
121→                            id);
122→                    }
123→
124→                    // Not found in hierarchy or no ServiceGroupId — mark as unknown.
125→                    this.cache[id] = UnknownParent;
126→                    results[id] = UnknownParent;
127→                }
128→            }
129→
130→            return results;
131→        }
132→
133→        private ParentServiceGroupInfo? MatchFromHierarchyNode(ServiceTreeNode node, ParentGroupCatalogSnapshot snapshot)
134→        {
135→            // Check each ancestor level by ID first, then by name.
136→            // Order: ServiceGroup → Organization → Division (most specific to least).
137→            string[] ancestorIds = new[]
138→            {
139→                node.ServiceGroupId,
140→                node.OrganizationId,
141→                node.DivisionId,
142→            };
143→
144→            foreach (var ancestorId in ancestorIds)
145→            {
146→                if (!string.IsNullOrWhiteSpace(ancestorId)
147→                    && snapshot.ParentsById.TryGetValue(ancestorId, out var match))
148→                {
149→                    return match;
150→                }
151→            }
152→
153→            string[] ancestorNames = new[]
154→            {
155→                node.ServiceGroupName,
156→                node.OrganizationName,
157→                node.DivisionName,
158→            };
159→
160→            foreach (var name in ancestorNames)
161→            {
162→                var nameMatch = this.MatchParentByName(name, snapshot);
163→                if (nameMatch != null)
164→                {
165→                    return nameMatch;
166→                }
167→            }
168→
169→            // No catalog match — but if the hierarchy provides a ServiceGroupId,
170→            // return it directly with empty Product.
171→            if (!string.IsNullOrWhiteSpace(node.ServiceGroupId))
172→            {
173→                return new ParentServiceGroupInfo(
174→                    node.ServiceGroupId,
175→                    node.ServiceGroupName ?? string.Empty,
176→                    string.Empty);
177→            }
178→
179→            return null;
180→        }
181→
182→        private ParentServiceGroupInfo? MatchParentByName(string name, ParentGroupCatalogSnapshot snapshot)
183→        {
184→            if (string.IsNullOrWhiteSpace(name))
185→            {
186→                return null;
187→            }
188→
189→            var normalizedName = this.NormalizeName(name);
190→            foreach (var parent in snapshot.ParentsByNameDescending)
191→            {
192→                if (this.NormalizeName(parent.ServiceGroupName) == normalizedName)
193→                {
194→                    return parent;
195→                }
196→            }
197→
198→            return null;
199→        }
200→
201→        private string NormalizeName(string input)
202→        {
203→            if (string.IsNullOrWhiteSpace(input))
204→            {
205→                return string.Empty;
206→            }
207→
208→            var normalized = input.Replace("&", "and", StringComparison.OrdinalIgnoreCase);
209→            var builder = new StringBuilder(normalized.Length);
210→            foreach (var ch in normalized)
211→            {
212→                if (char.IsLetterOrDigit(ch))
213→                {
214→                    builder.Append(char.ToLowerInvariant(ch));
215→                }
216→                else if (char.IsWhiteSpace(ch))
217→                {
218→                    builder.Append(' ');
219→                }
220→            }
221→
222→            return string.Join(' ', builder.ToString().Split(' ', StringSplitOptions.RemoveEmptyEntries));
223→        }
224→    }
225→}
