100→                        if (snapshotStarted)
101→                        {
102→                            lastConfigLogUtc = DateTime.UtcNow;
103→                        }
104→                    }
105→                    finally
106→                    {
107→                        snapshotScope?.Dispose();
108→                        updateScope?.Dispose();
109→                    }
110→
111→                    const int SleepIntervalInMS = 1000 * 300;  // 5 min
112→                    try
113→                    {
114→                        await Task.Delay(SleepIntervalInMS, stoppingToken);
115→                    }
116→                    catch (TaskCanceledException)
117→                    {
118→                        // Do nothing
119→                        break;
120→                    }
121→                }
122→
123→                logger.LogInformationEx("Stopped service");
124→            }
125→            catch (Exception e)
126→            {
127→                logger.LogErrorEx("Error occurred in CodexUpdaterService");
128→                logger.LogErrorEx(e.ToString());
129→                throw;
130→            }
131→            finally
132→            {
133→                this.hostApplicationLifeTime.StopApplication();
134→            }
135→        }
136→
137→        private async Task LogPapyrusConfigSnapshotAsync(
138→            IPapyrusConfigService papyrusConfigService,
139→            ILogger<CodexUpdaterService> logger,
140→            CancellationToken cancellationToken)
141→        {
142→            var collectedAtUtc = DateTime.UtcNow;
143→            var snapshotStopwatch = Stopwatch.StartNew();
144→            logger.LogInformationEx($"Starting LogPapyrusConfigSnapshotAsync at {collectedAtUtc:O}");
145→
146→            var quotaEntries = await papyrusConfigService.GetPapyrusControlAppQuotasAsync();
147→            var quotaSummaryEntries = await papyrusConfigService.GetModelQuotaSummariesAsync();
148→            var serviceAuthQuotaEntries = await papyrusConfigService.GetServiceQuotaAndAuthManagementAsync(string.Empty);
149→
150→            var quotaSummariesLookup = quotaSummaryEntries.ToDictionary(
151→                entry => $"{entry.ModelName}-{entry.TrafficGroup}",
152→                entry => entry.TotalConfiguredOnlineQuota,
153→                StringComparer.OrdinalIgnoreCase);
154→            var quotaSummaryHashLookup = quotaSummaryEntries.ToDictionary(
155→                entry => $"{entry.ModelName}-{entry.TrafficGroup}",
156→                entry => entry.ModelNameTrafficGroupHash,
157→                StringComparer.OrdinalIgnoreCase);
158→
159→            var serviceAuthQuotaLookup = serviceAuthQuotaEntries
160→                .Where(entry => !string.IsNullOrWhiteSpace(entry.QuotaAppId))
161→                .GroupBy(entry => entry.QuotaAppId, StringComparer.OrdinalIgnoreCase)
162→                .ToDictionary(group => group.Key, group => group.First(), StringComparer.OrdinalIgnoreCase);
163→
164→            var modelQuotaSummary = quotaEntries.Select(entry =>
165→            {
166→                var serviceAuthQuota = serviceAuthQuotaLookup.TryGetValue(entry.AppQuotaConfig.AppId, out var serviceAuthData)
167→                    ? serviceAuthData
168→                    : null;
169→
170→                var modelKey = $"{entry.ModelName}-{entry.TrafficGroup}";
171→
172→                return new
173→                {
174→                    CollectedAtUtc = collectedAtUtc,
175→                    entry.ModelName,
176→                    entry.TrafficGroup,
177→                    QuotaAppId = entry.AppQuotaConfig.AppId,
178→                    QuotaAllocated = entry.AppQuotaConfig.OnlineQuota,
179→                    ModelNameTrafficGroupHash = quotaSummaryHashLookup.TryGetValue(modelKey, out var modelHash)
180→                        ? modelHash
181→                        : string.Empty,
182→                    TotalConfiguredOnlineQuota = quotaSummariesLookup.TryGetValue(modelKey, out var totalQuota)
183→                        ? totalQuota
184→                        : 0.0,
185→                    ServiceTreeId = serviceAuthQuota?.ServiceTreeId ?? string.Empty,
186→                    ServiceName = serviceAuthQuota?.ServiceName ?? string.Empty,
187→                };
188→            }).ToList();
189→
190→            var endpointEntries = await papyrusConfigService.GetPapyrusControlEndpointsAsync();
191→            var endpointInfo = endpointEntries.Select(entry =>
192→            {
193→                var modelKey = $"{entry.ModelName}-{entry.TrafficGroup}";
194→                return new
195→                {
196→                    CollectedAtUtc = collectedAtUtc,
197→                    LoadBalancerModelName = entry.ModelName,
198→                    LoadBalancerTrafficGroup = entry.TrafficGroup,
199→                    EndpointUrl = entry.EndpointConfig.URL,
200→                    EndpointDeploymentId = entry.EndpointConfig.GlobalId,
201→                    TotalConfiguredOnlineQuota = quotaSummariesLookup.TryGetValue(modelKey, out var totalQuota)
202→                        ? totalQuota
203→                        : 0.0,
204→                    entry.EndpointConfig.SafeConcurrencyPerInstance,
205→                    entry.EndpointConfig.MaxConcurrencyPerInstance,
206→                    entry.EndpointConfig.Weight,
207→                };
208→            }).ToList();
209→
210→            var jsonOptions = new JsonSerializerOptions { WriteIndented = true };
211→            var quotaLogPayload = JsonSerializer.Serialize(
212→                new { CollectedAtUtc = collectedAtUtc, ModelQuotaSummary = modelQuotaSummary },
213→                jsonOptions);
214→
215→            var endpointLogPayload = JsonSerializer.Serialize(new { CollectedAtUtc = collectedAtUtc, EndpointInfo = endpointInfo }, jsonOptions);
216→
217→            logger.LogInformationEx($"PapyrusConfigSnapshot ModelQuotaSummary: {quotaLogPayload}");
218→            logger.LogInformationEx($"PapyrusConfigSnapshot EndpointInfo: {endpointLogPayload}");
219→            snapshotStopwatch.Stop();
220→            logger.LogInformationEx(
221→                $"Completed LogPapyrusConfigSnapshotAsync at {DateTime.UtcNow:O} in {snapshotStopwatch.Elapsed.TotalSeconds:F1}s");
222→        }
