namespace Microsoft.Falcon.CodexUpdater
{
    using System;
    using System.Collections.Generic;
    using System.Diagnostics;
    using System.Linq;
    using System.Text.Json;
    using System.Threading;
    using System.Threading.Tasks;
    using CodeXCore.Services;
    using Microsoft.Extensions.DependencyInjection;
    using Microsoft.Extensions.Hosting;
    using Microsoft.Extensions.Logging;
    using Microsoft.Falcon.LibOnePortal.Utility;

    /// <summary>
    /// A background service that updates Codex endpoints.
    /// </summary>
    public sealed class CodexUpdaterService : BackgroundService
    {
        /// <summary>
        /// Represents the default interval between configuration log entries.
        /// </summary>
        private static readonly TimeSpan ConfigLogInterval = TimeSpan.FromMinutes(30);

        /// <summary>
        /// The service provider.
        /// </summary>
        private readonly IServiceProvider serviceProvider;

        /// <summary>
        /// The host application lifetime.
        /// </summary>
        private readonly IHostApplicationLifetime hostApplicationLifeTime;

        /// <summary>
        /// Initializes a new instance of the <see cref="CodexUpdaterService"/> class.
        /// </summary>
        /// <param name="serviceProvider">The service provider.</param>
        /// <param name="hostApplicationLifeTime">The host application lifetime.</param>
        public CodexUpdaterService(IServiceProvider serviceProvider, IHostApplicationLifetime hostApplicationLifeTime)
        {
            this.serviceProvider = serviceProvider ?? throw new ArgumentNullException(nameof(serviceProvider));
            this.hostApplicationLifeTime = hostApplicationLifeTime ?? throw new ArgumentNullException(nameof(hostApplicationLifeTime));
        }

        /// <inheritdoc/>
        protected override async Task ExecuteAsync(CancellationToken stoppingToken)
        {
            var logger = this.serviceProvider.GetService<ILogger<CodexUpdaterService>>();
            var lastConfigLogUtc = DateTime.MinValue;
            try
            {
                while (!stoppingToken.IsCancellationRequested)
                {
                    IServiceScope updateScope = null;
                    IServiceScope snapshotScope = null;
                    Task updateTask = Task.CompletedTask;
                    Task snapshotTask = Task.CompletedTask;
                    var snapshotDue = DateTime.UtcNow - lastConfigLogUtc >= ConfigLogInterval;
                    var snapshotStarted = false;

                    try
                    {
                        updateScope = this.serviceProvider.CreateScope();
                        var codexService = updateScope.ServiceProvider.GetRequiredService<ICodeXService>();
                        var updateStartedAtUtc = DateTime.UtcNow;
                        var updateStopwatch = Stopwatch.StartNew();
                        logger.LogInformationEx($"start UpdateEndPointInfoV3Async at {updateStartedAtUtc:O}");
                        updateTask = codexService.UpdateEndPointInfoV3Async();
                        _ = updateTask.ContinueWith(
                            _ =>
                            {
                                updateStopwatch.Stop();
                                logger.LogInformationEx(
                                    $"UpdateEndPointInfoV3Async completed at {DateTime.UtcNow:O} in {updateStopwatch.Elapsed.TotalSeconds:F1}s");
                            },
                            TaskContinuationOptions.OnlyOnRanToCompletion);

                        if (snapshotDue)
                        {
                            snapshotScope = this.serviceProvider.CreateScope();
                            var papyrusConfigService = snapshotScope.ServiceProvider.GetService<IPapyrusConfigService>();
                            if (papyrusConfigService != null)
                            {
                                snapshotTask = this.LogPapyrusConfigSnapshotAsync(
                                    papyrusConfigService,
                                    logger,
                                    stoppingToken);
                                snapshotStarted = true;
                            }
                        }

                        await Task.WhenAll(updateTask, snapshotTask);

                        if (snapshotStarted)
                        {
                            lastConfigLogUtc = DateTime.UtcNow;
                        }
                    }
                    finally
                    {
                        snapshotScope?.Dispose();
                        updateScope?.Dispose();
                    }

                    const int SleepIntervalInMS = 1000 * 300;  // 5 min
                    try
                    {
                        await Task.Delay(SleepIntervalInMS, stoppingToken);
                    }
                    catch (TaskCanceledException)
                    {
                        // Do nothing
                        break;
                    }
                }

                logger.LogInformationEx("Stopped service");
            }
            catch (Exception e)
            {
                logger.LogErrorEx("Error occurred in CodexUpdaterService");
                logger.LogErrorEx(e.ToString());
                throw;
            }
            finally
            {
                this.hostApplicationLifeTime.StopApplication();
            }
        }

        private async Task LogPapyrusConfigSnapshotAsync(
            IPapyrusConfigService papyrusConfigService,
            ILogger<CodexUpdaterService> logger,
            CancellationToken cancellationToken)
        {
            var collectedAtUtc = DateTime.UtcNow;
            var snapshotStopwatch = Stopwatch.StartNew();
            logger.LogInformationEx($"Starting LogPapyrusConfigSnapshotAsync at {collectedAtUtc:O}");

            var quotaEntries = await papyrusConfigService.GetPapyrusControlAppQuotasAsync();
            var quotaSummaryEntries = await papyrusConfigService.GetModelQuotaSummariesAsync();
            var serviceAuthQuotaEntries = await papyrusConfigService.GetServiceQuotaAndAuthManagementAsync(string.Empty);

            var quotaSummariesLookup = quotaSummaryEntries.ToDictionary(
                entry => $"{entry.ModelName}-{entry.TrafficGroup}",
                entry => entry.TotalConfiguredOnlineQuota,
                StringComparer.OrdinalIgnoreCase);
            var quotaSummaryHashLookup = quotaSummaryEntries.ToDictionary(
                entry => $"{entry.ModelName}-{entry.TrafficGroup}",
                entry => entry.ModelNameTrafficGroupHash,
                StringComparer.OrdinalIgnoreCase);

            var serviceAuthQuotaLookup = serviceAuthQuotaEntries
                .Where(entry => !string.IsNullOrWhiteSpace(entry.QuotaAppId))
                .GroupBy(entry => entry.QuotaAppId, StringComparer.OrdinalIgnoreCase)
                .ToDictionary(group => group.Key, group => group.First(), StringComparer.OrdinalIgnoreCase);

            var modelQuotaSummary = quotaEntries.Select(entry =>
            {
                var serviceAuthQuota = serviceAuthQuotaLookup.TryGetValue(entry.AppQuotaConfig.AppId, out var serviceAuthData)
                    ? serviceAuthData
                    : null;

                var modelKey = $"{entry.ModelName}-{entry.TrafficGroup}";

                return new
                {
                    CollectedAtUtc = collectedAtUtc,
                    entry.ModelName,
                    entry.TrafficGroup,
                    QuotaAppId = entry.AppQuotaConfig.AppId,
                    QuotaAllocated = entry.AppQuotaConfig.OnlineQuota,
                    ModelNameTrafficGroupHash = quotaSummaryHashLookup.TryGetValue(modelKey, out var modelHash)
                        ? modelHash
                        : string.Empty,
                    TotalConfiguredOnlineQuota = quotaSummariesLookup.TryGetValue(modelKey, out var totalQuota)
                        ? totalQuota
                        : 0.0,
                    ServiceTreeId = serviceAuthQuota?.ServiceTreeId ?? string.Empty,
                    ServiceName = serviceAuthQuota?.ServiceName ?? string.Empty,
                };
            }).ToList();

            var endpointEntries = await papyrusConfigService.GetPapyrusControlEndpointsAsync();
            var endpointInfo = endpointEntries.Select(entry =>
            {
                var modelKey = $"{entry.ModelName}-{entry.TrafficGroup}";
                return new
                {
                    CollectedAtUtc = collectedAtUtc,
                    LoadBalancerModelName = entry.ModelName,
                    LoadBalancerTrafficGroup = entry.TrafficGroup,
                    EndpointUrl = entry.EndpointConfig.URL,
                    EndpointDeploymentId = entry.EndpointConfig.GlobalId,
                    TotalConfiguredOnlineQuota = quotaSummariesLookup.TryGetValue(modelKey, out var totalQuota)
                        ? totalQuota
                        : 0.0,
                    entry.EndpointConfig.SafeConcurrencyPerInstance,
                    entry.EndpointConfig.MaxConcurrencyPerInstance,
                    entry.EndpointConfig.Weight,
                };
            }).ToList();

            var jsonOptions = new JsonSerializerOptions { WriteIndented = true };
            var quotaLogPayload = JsonSerializer.Serialize(
                new { CollectedAtUtc = collectedAtUtc, ModelQuotaSummary = modelQuotaSummary },
                jsonOptions);

            var endpointLogPayload = JsonSerializer.Serialize(new { CollectedAtUtc = collectedAtUtc, EndpointInfo = endpointInfo }, jsonOptions);

            logger.LogInformationEx($"PapyrusConfigSnapshot ModelQuotaSummary: {quotaLogPayload}");
            logger.LogInformationEx($"PapyrusConfigSnapshot EndpointInfo: {endpointLogPayload}");
            snapshotStopwatch.Stop();
            logger.LogInformationEx(
                $"Completed LogPapyrusConfigSnapshotAsync at {DateTime.UtcNow:O} in {snapshotStopwatch.Elapsed.TotalSeconds:F1}s");
        }
    }
}

