138→            this.endpointUpdater.InitSKUList();
139→
140→            using (var transaction = this.unitOfCodeX.BeginTransaction())
141→            {
142→                try
143→                {
144→                    var modelScaleSets = await this.mssUpdater.GetModelScaleSetsAsync();
145→                    this.logger.LogInformationEx($"MSS 1.Get [{lastUpdateTime}]: [{modelScaleSets.Count()}]");
146→                    modelScaleSets.ToList().ForEach(mss => this.logger.LogInformationEx($"MSS 1.Get [{lastUpdateTime}]: Region: [{mss.Key}], ModelScaleSet: [{mss.Value}]"));
147→
148→                    var mpcpReservationsProm = await this.mssUpdater.GetMpcmReservations("PROM");
149→                    this.logger.LogInformationEx($"MPCM 2a.Get PROM [{lastUpdateTime}]: [{mpcpReservationsProm.Count()}]");
150→                    mpcpReservationsProm.ToList().ForEach(res => this.logger.LogInformationEx($"MPCM 2a.Get PROM [{lastUpdateTime}]: Region: [{res.Key}], MpcmReservation: [{res.Value}]"));
151→
152→                    var mpcpReservationsPromIB = await this.mssUpdater.GetMpcmReservations("PROM IB");
