179→                    updatedEPs.AddRange(await this.endpointUpdater.UpdateEndPointStatus2Async(lastUpdateTime, endpointToLoadBalancerStatus).ConfigureAwait(false));
180→                    this.logger.LogInformationEx("BinhuTest 1");
181→                    this.logger.LogInformationEx("UpdateEndPointStatus2Async is done");
182→                    updatedEPs.AddRange(await this.endpointUpdater.UpdateAOAIEndPointStatus2Async(lastUpdateTime, endpointToLoadBalancerStatus).ConfigureAwait(false));
183→                    this.logger.LogInformationEx("UpdateAOAIEndPointStatus2Async is done");
