246→        /// <summary>
247→        /// GetAllEndpointStatus2
248→        /// </summary>
249→        /// <returns>Endpoint Result List</returns>
250→        public IList<EndpointResult> GetAllEndpointStatus2()
251→        {
252→            var endpointResults = new List<EndpointResult>();
253→            var metaDatas = this.unitOfCodeX.EndpointStatusV3Repository.Entities.ToList();
254→            var quotas = this.unitOfCodeX.RegionStatusV3Repository.Entities.ToList();
255→            var endpoints = this.unitOfCodeX.EndpointV3Repository.Entities.ToList();
256→            var regions = this.unitOfCodeX.RegionRepository.Entities.ToList();
257→            var models = this.unitOfCodeX.ModelRepository.Entities.ToList();
258→            var skus = this.unitOfCodeX.SKUV3Repository.Entities.Include(e => e.SKUFamily).ToList();
259→            var aoaiDeployments = this.unitOfCodeX.AoaiDeploymentV3Repository.Entities.ToList();
260→            var aoaiTrafficDict = this.GetAoaiTrafficDict();
261→
262→            var modelScaleSets = this.unitOfCodeX.ModelScaleSetsStatusV1Repository.Entities.ToList();
263→            var mpcpReservations = this.unitOfCodeX.ReservationStatusV1Repository.Entities.ToList();
264→            var modelPools = this.unitOfCodeX.ModelPoolsStatusV1Repository.Entities.ToList();
265→
266→            var modelScaleSetMetaData = MssAndMpcmUtils.GetMssMetaData(this.logger, modelScaleSets);
267→            var mpcpMetaData = MssAndMpcmUtils.GetMpcmReservationMetaData(mpcpReservations);
268→
269→            var modelPoolMetaData = ModelPoolAndMpcmUtils.GetModelPoolMetaData(this.logger, modelPools);
270→            var mpcpModelPoolMetaData = ModelPoolAndMpcmUtils.GetMpcmReservationMetaData(mpcpReservations);
271→
272→            foreach (var metaData in metaDatas)
273→            {
274→                var endpoint = endpoints.FirstOrDefault(q => q.Id == metaData.EndpointId);
275→                if (endpoint == null)
276→                {
277→                    continue;
278→                }
279→
280→                var region = regions.FirstOrDefault(q => q.Id == endpoint.RegionId);
281→                var model = models.FirstOrDefault(q => q.Id == endpoint.ModelId);
282→                var aoaideploymentjson = aoaiDeployments.Where((deployment) => deployment.AmlEnpointId == endpoint.Id).FirstOrDefault()?.AoaiDeployment;
283→                string finalModelPoolName = string.Empty;
284→                if (!string.IsNullOrEmpty(aoaideploymentjson))
285→                {
286→                    AOAIDeployment aoaideployment = JsonSerializer.Deserialize<AOAIDeployment>(aoaideploymentjson);
287→                    if (aoaideployment.Tags.ContainsKey("modelPoolName"))
288→                    {
289→                        finalModelPoolName = aoaideployment.Tags["modelPoolName"];
290→                    }
291→                }
292→
293→                var sku = skus.FirstOrDefault(q => q.Id == metaData.SKUId);
294→                if (sku == null)
295→                {
296→                    throw new ApplicationException($"SKU Id {metaData.SKUId} in endpoint {endpoint.Name} ${endpoint.Id} can't be not found. It may due to data corruption in DB");
297→                }
298→
299→                var regionStatusItem = quotas.FirstOrDefault(q => q.RegionId == endpoint.RegionId && q.SKUFamilyId == (endpoint.IsLowPriority ? AzureConfig.RegionLowPriority : sku.SKUFamilyId));
300→                var interfacingAOAIs = aoaiDeployments.Where((deployment) => deployment.AmlEnpointId == endpoint.Id);
301→                var trafficGroupInfos = TrafficGroupUtil.GetTrafficGroupInfos(metaData.TrafficGroupSetting, metaData.TrafficGroupStatus, metaData.LoadBalancerStatus, metaData.DeploymentsStatus);
302→                this.AppendAOAIDataToAMLTrafficGroupInfo(trafficGroupInfos, interfacingAOAIs, aoaiTrafficDict);
303→
304→                var quotaType = endpoint.IsLowPriority ? AzureConfig.QuotaTypeLowPriority : sku.SKUFamily.QuotaType;
305→
306→                int? unknownQuota = null;
307→                var modelName = model.OverwriteName != null ? model.OverwriteName : model.Name;
308→
309→                // Get metadata from both MSS and ModelPool sources
310→                var endpointRevisedFromMss = MssAndMpcmUtils.ExtractMetadataFromMssAndMpcm(modelScaleSetMetaData, mpcpMetaData, region.Name, endpoint.Name);
311→                var endpointRevisedFromModelPool = ModelPoolAndMpcmUtils.ExtractMetadataFromMssAndMpcm(modelPoolMetaData, mpcpModelPoolMetaData, region.Name, endpoint.Name);
312→
313→                // Merge the two results, preferring non-null/non-empty values from MSS first, then falling back to ModelPool
314→                var endpointRevised = this.MergeEndpointRevised(endpointRevisedFromMss, endpointRevisedFromModelPool);
315→
316→                if (string.IsNullOrEmpty(finalModelPoolName) && endpointRevised != null && !string.IsNullOrEmpty(endpointRevised.MssPoolName))
317→                {
318→                    finalModelPoolName = endpointRevised.MssPoolName;
319→                }
320→
321→                // Use values from endpointRevised when SKU or ModelName is empty/null
322→                var finalSku = sku.InstanceTypeName;
323→                var finalQuotaType = quotaType;
324→                if (string.IsNullOrEmpty(finalSku) && endpointRevised != null && !string.IsNullOrEmpty(endpointRevised.SKU))
325→                {
326→                    finalSku = endpointRevised.SKU;
327→
328→                    // When SKU is overridden, try to update the quota type by looking up the SKU with the same InstanceTypeName
329→                    var matchingSku = skus.FirstOrDefault(s => s.InstanceTypeName.Equals(finalSku, StringComparison.OrdinalIgnoreCase));
330→                    if (matchingSku != null && matchingSku.SKUFamily != null)
331→                    {
332→                        finalQuotaType = endpoint.IsLowPriority ? AzureConfig.QuotaTypeLowPriority : matchingSku.SKUFamily.QuotaType;
333→                    }
334→                }
335→
336→                var finalModelName = modelName;
337→                if ((string.IsNullOrEmpty(finalModelName) || finalModelName.Equals(Constant.UnknownModelName)) && endpointRevised != null && !string.IsNullOrEmpty(endpointRevised.MssModelDefName))
338→                {
339→                    finalModelName = endpointRevised.MssModelDefName;
340→                }
341→
342→                this.UpdateTrafficGroupGpuCount(trafficGroupInfos, endpointRevised?.TrafficGroup);
343→
344→                var endpointResult = new EndpointResult(
345→                        EndpointId: endpoint.Id,
346→                        Name: endpoint.Name,
347→                        ModelName: finalModelName,
348→                        QuotaType: finalQuotaType,
349→                        SKU: finalSku,
350→                        RegionName: region.Name,
351→                        UsedGPUCount: endpointRevised?.AllGpuCount ?? metaData.CountsPerSKU,
352→                        InstanceCount: endpointRevised?.AllReservedInstanceCount ?? metaData.InstanceCount,
353→                        TrafficGroup: trafficGroupInfos,
354→                        TimeStampDateTime: metaData.TimeStamp,
355→                        RegionUsedGPU: regionStatusItem?.UsedQuota ?? unknownQuota,
356→                        RegionTotalGPU: regionStatusItem?.TotalQuota ?? unknownQuota,
357→                        ModelPoolName: finalModelPoolName,
358→                        EndpointType: endpointRevised?.EndpointType ?? EndpointType.Standard,
359→                        ItsEnsemblePrimary: endpointRevised?.ItsEnsemblePrimary ?? string.Empty);
360→
361→                endpointResults.Add(endpointResult);
362→            }
363→
364→            return endpointResults;
365→        }
