654→        /// <summary>
655→        /// Merges two EndpointResultRevised objects, preferring non-null/non-empty values from the first object,
656→        /// falling back to the second object when the first has null or empty values.
657→        /// </summary>
658→        /// <param name="first">The primary EndpointResultRevised object (from MSS).</param>
659→        /// <param name="second">The fallback EndpointResultRevised object (from ModelPool).</param>
660→        /// <returns>A merged EndpointResultRevised object, or null if both inputs are null.</returns>
661→        private EndpointResultRevised MergeEndpointRevised(EndpointResultRevised first, EndpointResultRevised second)
662→        {
663→            // If both are null, return null
664→            if (first == null && second == null)
665→            {
666→                return null;
667→            }
668→
669→            // If only one is null, return the other
670→            if (first == null)
671→            {
672→                return second;
673→            }
674→
675→            if (second == null)
676→            {
677→                return first;
678→            }
679→
680→            // Merge properties: prefer first if it's non-null/non-empty, otherwise use second
681→            var mergedRegion = !string.IsNullOrEmpty(first.Region) ? first.Region : second.Region;
682→            var mergedEndpointUrl = !string.IsNullOrEmpty(first.EndpointUrl) ? first.EndpointUrl : second.EndpointUrl;
683→            var mergedMssPoolName = !string.IsNullOrEmpty(first.MssPoolName) ? first.MssPoolName : second.MssPoolName;
684→            var mergedMssModelDefName = !string.IsNullOrEmpty(first.MssModelDefName) ? first.MssModelDefName : second.MssModelDefName;
685→            var mergedSku = !string.IsNullOrEmpty(first.SKU) ? first.SKU : second.SKU;
686→
687→            // endpointType and ItsEnsemblePrimary: prefer first
688→            var mergedEndpointType = first.EndpointType;
689→            var mergedItsEnsemblePrimary = first.ItsEnsemblePrimary;
690→
691→            // Merge traffic groups: prefer first if it has items, otherwise use second
692→            var mergedTrafficGroup = (first.TrafficGroup != null && first.TrafficGroup.Any()) ? first.TrafficGroup : second.TrafficGroup;
693→
694→            // For numeric values, prefer first if non-zero, otherwise use second
695→            var mergedAllGpuCount = first.AllGpuCount != 0 ? first.AllGpuCount : second.AllGpuCount;
696→            var mergedAllRequestedInstanceCount = first.AllRequestedInstanceCount != 0 ? first.AllRequestedInstanceCount : second.AllRequestedInstanceCount;
697→            var mergedAllReservedInstanceCount = first.AllReservedInstanceCount != 0 ? first.AllReservedInstanceCount : second.AllReservedInstanceCount;
698→
699→            return new EndpointResultRevised(
700→                mergedRegion,
701→                mergedEndpointUrl,
702→                mergedMssPoolName,
703→                mergedMssModelDefName,
704→                mergedSku,
705→                mergedEndpointType,
706→                mergedItsEnsemblePrimary,
707→                mergedTrafficGroup,
708→                mergedAllGpuCount,
709→                mergedAllRequestedInstanceCount,
710→                mergedAllReservedInstanceCount);
711→        }
712→
713→        private void UpdateTrafficGroupGpuCount(List<EndpointResult.TrafficGroupInfo> trafficGroups, IEnumerable<EndpointResultRevised.TrafficGroupInfo> revisedTrafficGroups)
714→        {
715→            if (revisedTrafficGroups == null || !revisedTrafficGroups.Any())
716→            {
717→                return;
718→            }
719→
720→            for (int i = 0; i < trafficGroups.Count; i++)
721→            {
722→                var revisedTrafficGroup = revisedTrafficGroups.FirstOrDefault(g => g.AoaiDeploymentSuffix == trafficGroups[i].Name);
723→                if (revisedTrafficGroup != null)
724→                {
725→                    // Use 'with' expression to create a new record with updated UsedGPUs
726→                    trafficGroups[i] = trafficGroups[i] with { UsedGPUs = revisedTrafficGroup.UsedGPUs };
727→                }
728→            }
729→        }
730→    }
731→}

