221→        /// <inheritdoc/>
222→        public async Task<ValidationResult> CheckConfigChangeSetAuthorizationAsync(PapyrusConfigChangeSet changeSet, ClaimsPrincipal user)
223→        {
224→            var permissions = await this.rolePermissionService.GetUserRolePermissionsAsync(user);
225→            var userIsAdmin = permissions.HasRole(RolePermissionConstants.Roles.Admin, RolePermissionConstants.Namespaces.Papyrus);
226→
227→            // If local environment is in test mode, userAlias uses the Mock Test User alias instead of the alias from the token
228→            var userAlias = PermissionHelper.GetUserAlias(user);
229→            var userIsCodexUser = permissions.HasRole(RolePermissionConstants.Roles.User, RolePermissionConstants.Namespaces.Papyrus);
230→
231→            // TODO: Consider accumulating multiple authorization/validation errors instead of returning on first failure.
232→            if (!userIsAdmin && !userIsCodexUser)
233→            {
234→                return new ValidationResult(false, $"User with alias '{userAlias}' must be a Codex portal user to submit PR requests");
235→            }
236→
237→            if (changeSet.AutoMerge && !userIsAdmin)
238→            {
239→                var autoMergeValidation = ValidateAutoMergePermissions(changeSet, permissions);
240→                if (!autoMergeValidation.Result)
241→                {
242→                    return autoMergeValidation;
243→                }
244→            }
245→
246→            // Handle app quota commands (create/delete/update) - allow organization owners
247→            if (changeSet.AppQuotaCreateCommands.Any() ||
248→                changeSet.AppQuotaDeleteCommands.Any() ||
249→                changeSet.AppQuotaUpdateCommands.Any())
250→            {
251→                if (!userIsAdmin)
252→                {
253→                    // Combine all app IDs from create, delete, and update commands
254→                    var allAppIds = changeSet.AppQuotaCreateCommands.Select(cmd => cmd.AppQuotaConfig.AppId)
255→                        .Concat(changeSet.AppQuotaDeleteCommands.Select(cmd => cmd.AppQuotaConfig.AppId))
256→                        .Concat(changeSet.AppQuotaUpdateCommands.Select(cmd => cmd.AppQuotaConfig.AppId))
257→                        .ToList();
258→
259→                    var ownershipValidation = await this.ValidateOrganizationOwnershipAsync(user, allAppIds, userAlias);
260→                    if (!ownershipValidation.Result)
261→                    {
262→                        return ownershipValidation;
263→                    }
264→                }
265→            }
266→
267→            if ((changeSet.ServiceAuthQuotaDeleteCommands.Any() ||
268→                changeSet.ServiceAuthQuotaUpdateCommands.Any()) &&
269→                !userIsAdmin)
270→            {
271→                var targetQuotaAppIds = changeSet.ServiceAuthQuotaDeleteCommands.Select(cmd => cmd.QuotaAppId)
272→                    .Concat(changeSet.ServiceAuthQuotaUpdateCommands.Select(cmd => cmd.QuotaAppId))
273→                    .ToList();
274→
275→                var ownershipValidation = await this.ValidateOrganizationOwnershipAsync(user, targetQuotaAppIds, userAlias);
276→                if (!ownershipValidation.Result)
277→                {
278→                    return ownershipValidation;
279→                }
280→            }
281→
282→            return new ValidationResult(true, null);
283→        }
