285→        /// <summary>
286→        /// Validate that all GUIDs in the ServiceAuthQuota commands are valid GUIDs.
287→        /// </summary>
288→        /// <param name="changeSet">the request contains the changes</param>
289→        /// <returns>true if validate, false otherwise</returns>
290→        public ValidationResult ValidateChangeSetGuids(PapyrusConfigChangeSet changeSet)
291→        {
292→            if (!changeSet.ServiceAuthQuotaCreateCommands.Any() &&
293→                !changeSet.ServiceAuthQuotaUpdateCommands.Any())
294→            {
295→                return new ValidationResult(true, null);
296→            }
297→
298→            var invalidServiceTreeIds = changeSet.ServiceAuthQuotaCreateCommands.Select(s => s.ServiceTreeId)
299→                ?.Concat(changeSet.ServiceAuthQuotaUpdateCommands.Select(s => s.ServiceTreeId))
300→                ?.Where(id => !IsValidGuid(id))
301→                ?.ToList();
302→
303→            if (invalidServiceTreeIds.Any())
304→            {
305→                return new ValidationResult(false, $"Invalid ServiceTreeIds found: {string.Join(", ", invalidServiceTreeIds)}");
306→            }
307→
308→            var invalidAppIds = (changeSet.ServiceAuthQuotaCreateCommands ?? Enumerable.Empty<ServiceAuthQuotaManagementCreateCommand>()).SelectMany(s => s.AppIds ?? Enumerable.Empty<string>())
309→                .Concat((changeSet.ServiceAuthQuotaUpdateCommands ?? Enumerable.Empty<ServiceAuthQuotaManagementUpdateCommand>()).SelectMany(s => s.AppIds ?? Enumerable.Empty<string>()))
310→                .Where(id => id != null && !IsValidGuid(id))
311→                .ToList();
312→
313→            if (invalidAppIds.Any())
314→            {
315→                return new ValidationResult(false, $"Invalid AppIds found: {string.Join(", ", invalidAppIds)}");
316→            }
317→
318→            var invalidRoles = (changeSet.ServiceAuthQuotaCreateCommands ?? Enumerable.Empty<ServiceAuthQuotaManagementCreateCommand>()).SelectMany(s => s.Roles ?? Enumerable.Empty<string>())
319→                .Concat((changeSet.ServiceAuthQuotaUpdateCommands ?? Enumerable.Empty<ServiceAuthQuotaManagementUpdateCommand>()).SelectMany(s => s.Roles ?? Enumerable.Empty<string>()))
320→                .Where(id => !IsValidGuid(id))
321→                .ToList();
322→
323→            if (invalidRoles.Any())
324→            {
325→                return new ValidationResult(false, $"Invalid Roles found: {string.Join(", ", invalidRoles)}");
326→            }
327→
328→            return new ValidationResult(true, null);
329→        }
