336→        private static bool HasOwnershipForAppId(string appId, ISet<string> ownedAppIds)
337→        {
338→            if (string.IsNullOrWhiteSpace(appId) || ownedAppIds == null || ownedAppIds.Count == 0)
339→            {
340→                return false;
341→            }
342→
343→            var normalized = appId.Trim();
344→            while (!string.IsNullOrEmpty(normalized))
345→            {
346→                if (ownedAppIds.Contains(normalized))
347→                {
348→                    return true;
349→                }
350→
351→                var separatorIndex = normalized.LastIndexOf('/');
352→                if (separatorIndex <= 0)
353→                {
354→                    break;
355→                }
356→
357→                normalized = normalized.Substring(0, separatorIndex);
358→            }
359→
360→            return false;
361→        }
