363→        private static ValidationResult ValidateAutoMergePermissions(PapyrusConfigChangeSet changeSet, UserRolePermissions permissions)
364→        {
365→            var ownedModelTrafficGroups = GetOwnedModelTrafficGroupKeys(permissions);
366→
367→            var glbsBeingCreated = (changeSet.ModelTrafficGroupCreateCommands ?? Enumerable.Empty<ModelTrafficGroupCreateCommand>())
368→                .Select(cmd => $"{cmd.ModelName}-{cmd.TrafficGroup}")
369→                .Where(key => !string.IsNullOrWhiteSpace(key))
370→                .ToHashSet(StringComparer.OrdinalIgnoreCase);
371→
372→            var mtgKeys = NormalizeDistinct(GetModelTrafficGroupKeysRequiringOwnership(changeSet));
373→            var nonOwnedMtgKeys = GetNonOwnedKeys(mtgKeys, ownedModelTrafficGroups, glbsBeingCreated);
374→            if (nonOwnedMtgKeys.Any())
375→            {
376→                return new ValidationResult(
377→                    false,
378→                    $"Auto-approval requires model traffic group ownership for: {string.Join(", ", nonOwnedMtgKeys)}");
379→            }
380→
381→            var appQuotaCreateMtgKeys = NormalizeDistinct(GetAppQuotaCreateModelTrafficGroupKeys(changeSet));
382→            var nonOwnedAppQuotaCreateMtgKeys = GetNonOwnedKeys(appQuotaCreateMtgKeys, ownedModelTrafficGroups, glbsBeingCreated);
383→            if (nonOwnedAppQuotaCreateMtgKeys.Any())
384→            {
385→                return new ValidationResult(
386→                    false,
387→                    $"Auto-approval requires model traffic group ownership for new app quota entries: {string.Join(", ", nonOwnedAppQuotaCreateMtgKeys)}");
388→            }
389→
390→            var ownedQuotaAppIds = GetOwnedQuotaAppIds(permissions);
391→            var nonOwnedAppQuotaAppIds = GetNonOwnedQuotaAppIds(
392→                GetAppQuotaEntries(changeSet),
393→                ownedModelTrafficGroups,
394→                glbsBeingCreated,
395→                ownedQuotaAppIds);
396→            if (nonOwnedAppQuotaAppIds.Any())
397→            {
398→                return new ValidationResult(
399→                    false,
400→                    $"Auto-approval requires quota app ID ownership for: {string.Join(", ", nonOwnedAppQuotaAppIds)}");
401→            }
402→
403→            var targetQuotaAppIds = NormalizeDistinct(GetServiceAuthQuotaAppIds(changeSet));
404→            var nonOwnedServiceAuthQuotaAppIds = targetQuotaAppIds
405→                .Where(appId => !HasOwnershipForAppId(appId, ownedQuotaAppIds))
406→                .ToList();
407→
408→            if (nonOwnedServiceAuthQuotaAppIds.Any())
409→            {
410→                return new ValidationResult(
411→                    false,
412→                    $"Auto-approval requires service auth quota ownership for: {string.Join(", ", nonOwnedServiceAuthQuotaAppIds)}");
413→            }
414→
415→            return new ValidationResult(true, null);
416→        }
