557→        private static IEnumerable<string> GetServiceAuthQuotaAppIds(PapyrusConfigChangeSet changeSet)
558→        {
559→            if (changeSet == null)
560→            {
561→                yield break;
562→            }
563→
564→            foreach (var command in changeSet.ServiceAuthQuotaCreateCommands ?? Enumerable.Empty<ServiceAuthQuotaManagementCreateCommand>())
565→            {
566→                yield return command.QuotaAppId;
567→            }
568→
569→            foreach (var command in changeSet.ServiceAuthQuotaUpdateCommands ?? Enumerable.Empty<ServiceAuthQuotaManagementUpdateCommand>())
570→            {
571→                yield return command.QuotaAppId;
572→            }
573→
574→            foreach (var command in changeSet.ServiceAuthQuotaDeleteCommands ?? Enumerable.Empty<ServiceAuthQuotaManagementDeleteCommand>())
575→            {
576→                yield return command.QuotaAppId;
577→            }
578→        }
