358→        /// <summary>
359→        /// refrest and get pull requests.
360→        /// </summary>
361→        /// <param name="filter">optional filter.</param>
362→        /// <returns>list of pull request objects.</returns>
363→        public async Task<IList<PapyrusPullRequest>> GetPullRequestsAsync(PapyrusPRFilter? filter)
364→        {
365→            var cap = this.papyrusEnvProps;
366→            var currentEnvPrs = this.unitOfCodeX.PapyrusPullRequestRepository.Entities.Where(p => p.AdoOrg == cap.AdoOrg && p.AdoProject == cap.AdoProject && p.AdoRepo == cap.AdoRep);
367→            var prsToPoll = currentEnvPrs.Where(p => p.Status == PullRequestStatus.Active);
368→
369→            var adoPRs = await this.pullRequestClient.GetPullRequestsBatchAsync(prsToPoll.Select(p => p.PullRequestId).ToList());
370→            foreach (var adoPR in adoPRs)
371→            {
372→                var dbPr = prsToPoll.FirstOrDefault(g => g.PullRequestId == adoPR.PullRequestId);
373→                if (dbPr != null)
374→                {
375→                    this.UpdatePapyrusPullRequestFromPollInfo(dbPr, adoPR);
376→                }
377→            }
378→
379→            if (cap.CheckDeploymentStatus)
380→            {
381→                await this.PollPRDeploymentStatusAsync(currentEnvPrs.Where(p => p.Status == PullRequestStatus.Completed));
382→            }
383→
384→            this.unitOfCodeX.Save();
385→
386→            return this.ApplyFilter(currentEnvPrs, filter).ToList();
387→        }
