467→        /// <inheritdoc/>
468→        public PapyrusAppOrg UpdatePapyrusAppOrganizationOwnersList(PapyrusAppOrg updatedOrg)
469→        {
470→            var validatedOrg = this.ValidateOrganizationOwners(updatedOrg);
471→            var orgToUpdate = this.unitOfCodeX.PapyrusAppOrganizationRepository.Entities.Include(c => c.Ownerships).Where((org) => org.Id == validatedOrg.Id).FirstOrDefault()
472→                ?? throw new KeyNotFoundException($"Organization with id ({validatedOrg.Id}) is not found");
473→
474→            var existingOwners = orgToUpdate.Ownerships.ToList().Select(o => o.Alias);
475→            var aliasesToRemove = existingOwners.Where(alias => !validatedOrg.Owners.Contains(alias)).ToList();
476→
477→            // Find aliases to add (exist in new list but not in DB)
478→            var aliasesToAdd = validatedOrg.Owners.Where(alias => !existingOwners.Contains(alias)).ToList();
479→
480→            // Remove ownerships
481→            foreach (var alias in aliasesToRemove)
482→            {
483→                var ownershipToRemove = this.unitOfCodeX.OrganizationOwnershipRepository.Entities.FirstOrDefault(o => o.OrganizationId == orgToUpdate.Id && o.Alias == alias);
484→                orgToUpdate.Ownerships.Remove(ownershipToRemove);
485→            }
486→
487→            // Add new ownerships
488→            foreach (var alias in aliasesToAdd)
489→            {
490→                orgToUpdate.Ownerships.Add(new OrganizationOwnership
491→                {
492→                    Alias = alias,
493→                });
494→            }
495→
496→            this.unitOfCodeX.PapyrusAppOrganizationRepository.Update(orgToUpdate);
