623→        /// <summary>
624→        /// Apply filter.
625→        /// </summary>
626→        /// <param name="prs">PRs.</param>
627→        /// <param name="filter">filter.</param>
628→        /// <returns>filtered pull requests.</returns>
629→        private IQueryable<PapyrusPullRequest> ApplyFilter(IQueryable<PapyrusPullRequest> prs, PapyrusPRFilter? filter)
630→        {
631→            if (filter == null)
632→            {
633→                return prs;
634→            }
635→
636→            var filtered = prs.Where(pr =>
637→                    (filter.Owner == null || pr.Owner.Contains(filter.Owner)) &&
638→                    (filter.Status == PullRequestStatus.All || pr.Status == filter.Status));
639→
640→            if (filter.SortBy == PapyrusPRFilter.SortField.Status)
641→            {
642→                filtered = filter.SortAsc ? filtered.OrderBy(pr => pr.Status) : filtered.OrderByDescending(pr => pr.Status);
643→            }
644→            else if (filter.SortBy == PapyrusPRFilter.SortField.Owner)
645→            {
646→                filtered = filter.SortAsc ? filtered.OrderBy(pr => pr.Owner) : filtered.OrderByDescending(pr => pr.Owner);
647→            }
648→            else if (filter.SortBy == PapyrusPRFilter.SortField.CreationDate)
649→            {
650→                filtered = filter.SortAsc ? filtered.OrderBy(pr => pr.CreationDate) : filtered.OrderByDescending(pr => pr.CreationDate);
651→            }
652→
653→            return filtered;
654→        }
