264→        /// <param name="oneportalConfig">one portal config.</param>
265→        private static void AddFalconAADAuthentication(
266→            IWebHostEnvironment webhostEnv,
267→            IServiceCollection services,
268→            IConfiguration config,
269→            ICredentialFactory credentialFactory,
270→            OnePortalConfig oneportalConfig)
271→        {
272→            if (config == null)
273→            {
274→                throw new ArgumentNullException(nameof(config));
275→            }
276→
277→            services.AddAuthentication(options =>
278→            {
279→                // Use the policy scheme that will decide between Cookie or JWT
280→                options.DefaultScheme = "CookieOrJwt";
281→            })
282→            .AddPolicyScheme("CookieOrJwt", "Cookie or JWT", options =>
283→            {
284→                // Dynamically choose the authentication scheme based on the request
285→                options.ForwardDefaultSelector = context =>
286→                {
287→                    // If there's an Authorization header, fall back to JWT
288→                    if (context.Request.Headers.ContainsKey("Authorization"))
289→                    {
290→                        return JwtBearerDefaults.AuthenticationScheme;
291→                    }
292→                    else
293→                    {
294→                        // Else, use cookie auth.
295→                        return OpenIdConnectDefaults.AuthenticationScheme;
296→                    }
297→                };
298→            })
299→            .AddJwtBearer(opt =>
300→            {
301→                opt.Audience = oneportalConfig.AADAuthAppId;
302→                opt.Authority = $"https://login.microsoftonline.com/{LibOnePortal.Secret.Constants.MsftTenentId}/v2.0";
303→                opt.SaveToken = true;
304→                opt.TokenValidationParameters = GetTokenValidationParameters(oneportalConfig);
305→            })
306→            .AddMicrosoftIdentityWebApp(options =>
307→            {
308→                options.ClientId = oneportalConfig.AADAuthAppId;
309→                options.TenantId = LibOnePortal.Secret.Constants.MsftTenentId;
310→                options.Instance = "https://login.microsoftonline.com/";
311→                options.CallbackPath = "/signin-oidc";
312→                options.SaveTokens = true;
313→            });
314→
315→            // Please refer to https://github.com/AzureAD/microsoft-identity-web/issues/115,
316→            // it seems that this is a bug in azure container
317→            services.Configure<Microsoft.AspNetCore.Authentication.OpenIdConnect.OpenIdConnectOptions>(
318→                OpenIdConnectDefaults.AuthenticationScheme,
319→                options =>
320→                {
321→                    var redirectToIdpHandler = options.Events.OnRedirectToIdentityProvider;
322→                    options.Events.OnRedirectToIdentityProvider = async context =>
323→                    {
324→                        await redirectToIdpHandler(context);
325→                        context.ProtocolMessage.RedirectUri = ConstructRedirectUri(context.Request);
326→
327→                        // context.ProtocolMessage.PostLogoutRedirectUri = "your post logout URI";
328→                    };
329→                });
330→
331→            if (!webhostEnv.IsDevelopment() && !webhostEnv.IsTesting())
332→            {
333→                var pmeTokenCred = credentialFactory.CreateTokenCredential(ISExpAuthToolkit.AADTenant.PME);
334→                var msftTokenCred = credentialFactory.CreateTokenCredential();
335→                const string StorageAccountName = "bingoneportalstorage";
336→
337→                // Use the new Azure SDK approach with BlobContainerClient
338→                var blobUri = new Uri($"https://{StorageAccountName}.blob.core.windows.net/bingoneportaldataprotection/oneportaltemplatekeys.xml");
339→                var keyUri = new Uri($"{LibOnePortal.Secret.Constants.KeyVaultURL}{LibOnePortal.Secret.Constants.ProtectionKeyURI}");
340→
341→                // TO be done, move all to PME get rid of MSFT dependency.
342→                services.AddDataProtection()
343→                    .PersistKeysToAzureBlobStorage(blobUri, pmeTokenCred)
344→                    .ProtectKeysWithAzureKeyVault(keyUri, msftTokenCred);
345→            }
346→        }
347→
348→        /// <summary>
349→        /// GetTokenValidationParameters.
350→        /// </summary>
351→        /// <param name="config">config.</param>
352→        /// <returns>token parameters.</returns>
353→        private static TokenValidationParameters GetTokenValidationParameters(OnePortalConfig config)
354→        {
355→            if (config.EnablePmeAndMsftApiAccess)
356→            {
357→                return new TokenValidationParameters
358→                {
359→                    ValidAudiences = [config.AADAuthAppId, $"api://{config.AADAuthAppId}"],
360→                    ValidIssuers = [$"https://sts.windows.net/{ISExpAuthToolkit.Constants.MsftTenantId}/", $"https://sts.windows.net/{ISExpAuthToolkit.Constants.PmeTenantId}/"],
361→                };
362→            }
363→            else
364→            {
365→                return new TokenValidationParameters();
366→            }
367→        }
368→
369→        /// <summary>
370→        /// Constructs the redirect URI.
371→        /// </summary>
372→        /// <param name="request">The HTTP request.</param>
373→        /// <returns>The constructed redirect URI.</returns>
374→        private static string ConstructRedirectUri(HttpRequest request)
375→        {
376→            var sb = new StringBuilder();
377→
378→            // In local box we use http, in real environments, we use https
379→            if (request.Host.Value.StartsWith("localhost", StringComparison.InvariantCultureIgnoreCase))
380→            {
381→                sb.Append("http://");
382→            }
383→            else
384→            {
385→                sb.Append("https://");
386→            }
387→
388→            sb.Append(request.Host.Value);
389→            sb.Append("/signin-oidc");
390→            return sb.ToString();
391→        }
392→    }
393→}
