            var serviceProvider = services.BuildServiceProvider();
#pragma warning restore ASP0000 // Do not call 'IServiceCollection.BuildServiceProvider' in 'ConfigureServices'
            var config = serviceProvider.GetService<IConfiguration>();
            var webHostEnv = serviceProvider.GetService<IWebHostEnvironment>();
            var falconCredentialFactory = serviceProvider.GetService<ICredentialFactory>();
            OnePortalServiceCollectionExtension.AddFalconAADAuthentication(webHostEnv!, services, config!, falconCredentialFactory!, oneportalConfig);

            services.AddControllers().AddNewtonsoftJson(options =>
            {
                options.SerializerSettings.ContractResolver = new DefaultContractResolver();
            });
            services.Configure<WarmupOptions>(opts =>
            {
                opts.WarmupTimeout = TimeSpan.FromMinutes(1);
                opts.ContinueOnWarmupError = false;
                opts.ExecuteInParallel = false;
            });
            services.AddWarmup();
            services.AddTransient<IWarmupTask, ServiceWarmupTask>();

            var certPath = Environment.GetEnvironmentVariable("HTTPS_CERTIFICATE_FILE_PATH");
            if (!string.IsNullOrEmpty(certPath))
            {
                services.Configure<Microsoft.Falcon.Loader.DynamicHttpsCertificateOptions>(options =>
                {
                    options.EnableDynamicHttpsCertificateRefresh = true;
                    options.HttpsCertificateFilePath = certPath;
                });
            }
        }

        /// <summary>
        /// Adds OnePortal Falcon services for web portal.
        /// </summary>
        /// <param name="services">The service collection to add the services to.</param>
        /// <param name="portalName">The name of the portal.</param>
        /// <param name="oneportalConfig">oneportalconfig.</param>
        public static void AddOnePortalFalconServices(this IServiceCollection services, string portalName, OnePortalConfig oneportalConfig)
        {
            // Do the shared setup for backend service
            AddOnePortalFalconBackendServices(services, portalName);

            // We can't use DI in this function as DI is not setup before this service is called
#pragma warning disable ASP0000 // Do not call 'IServiceCollection.BuildServiceProvider' in 'ConfigureServices'
            var serviceProvider = services.BuildServiceProvider();
#pragma warning restore ASP0000 // Do not call 'IServiceCollection.BuildServiceProvider' in 'ConfigureServices'
            var config = serviceProvider.GetService<IConfiguration>();
            var webHostEnv = serviceProvider.GetService<IWebHostEnvironment>();
            var falconCredentialFactory = serviceProvider.GetService<ICredentialFactory>();
            AddFalconAADAuthentication(webHostEnv!, services, config!, falconCredentialFactory!, oneportalConfig);

            services.AddControllers().AddNewtonsoftJson(options =>
            {
                options.SerializerSettings.ContractResolver = new DefaultContractResolver();
            });
            services.Configure<WarmupOptions>(opts =>
            {
                opts.WarmupTimeout = TimeSpan.FromMinutes(1);
                opts.ContinueOnWarmupError = false;
                opts.ExecuteInParallel = false;
            });
            services.AddWarmup();
            services.AddTransient<IWarmupTask, ServiceWarmupTask>();

            if (!oneportalConfig.EnableProxy)
            {
                ConfigureSwagger(services);
                services.AddRazorPages().AddMvcOptions(options =>
                {
                    var policy = new AuthorizationPolicyBuilder()
                                  .RequireAuthenticatedUser()
                                  .Build();
                    options.Filters.Add(new AuthorizeFilter(policy));
                }).AddMicrosoftIdentityUI();

                // In production, the React files will be served from this directory
                services.AddSpaStaticFiles(configuration =>
                {
                    configuration.RootPath = "ClientApp/build";
                });
            }

            var certPath = Environment.GetEnvironmentVariable("HTTPS_CERTIFICATE_FILE_PATH");
            if (!string.IsNullOrEmpty(certPath))
            {
                services.Configure<Microsoft.Falcon.Loader.DynamicHttpsCertificateOptions>(options =>
                {
                    options.EnableDynamicHttpsCertificateRefresh = true;
                    options.HttpsCertificateFilePath = certPath;
                });
            }
        }

        private static void ConfigureSwagger(IServiceCollection services)
        {
            services.AddSwaggerGen(c =>
            {
                // Define the OAuth2.0 scheme that's in use (i.e. Implicit Flow)
                c.AddSecurityDefinition("oauth2", new OpenApiSecurityScheme
                {
                    Type = SecuritySchemeType.OAuth2,
                    Flows = new OpenApiOAuthFlows
                    {
                        Implicit = new OpenApiOAuthFlow
                        {
                            AuthorizationUrl = new Uri($"https://login.microsoftonline.com/{LibOnePortal.Secret.Constants.MsftTenentId}/oauth2/v2.0/authorize"),
                            TokenUrl = new Uri($"https://login.microsoftonline.com/{LibOnePortal.Secret.Constants.MsftTenentId}/oauth2/v2.0/authorize"),
                            Scopes = new Dictionary<string, string>
                            {
                                { "User.Read", "Access all endpoints for this app" },
                            },
                        },
                    },
                });

                c.AddSecurityRequirement(new OpenApiSecurityRequirement
                {
                    {
                        new OpenApiSecurityScheme
                        {
                            Reference = new OpenApiReference
                            {
                                Type = ReferenceType.SecurityScheme,
                                Id = "oauth2",
                            },
                        },
                        new string[] { "User.Read" }
                    },
                });
            });
        }

        /// <summary>
        /// Adds Falcon AAD authentication.
        /// </summary>
        /// <param name="webhostEnv">The web host environment.</param>
        /// <param name="services">The service collection to add the services to.</param>
        /// <param name="config">The configuration.</param>
        /// <param name="credentialFactory">The credential factory.</param>
        /// <param name="oneportalConfig">one portal config.</param>
        private static void AddFalconAADAuthentication(
            IWebHostEnvironment webhostEnv,
            IServiceCollection services,
            IConfiguration config,
            ICredentialFactory credentialFactory,
            OnePortalConfig oneportalConfig)
        {
            if (config == null)
            {
                throw new ArgumentNullException(nameof(config));
            }

            services.AddAuthentication(options =>
            {
                // Use the policy scheme that will decide between Cookie or JWT
                options.DefaultScheme = "CookieOrJwt";
            })
            .AddPolicyScheme("CookieOrJwt", "Cookie or JWT", options =>
            {
                // Dynamically choose the authentication scheme based on the request
                options.ForwardDefaultSelector = context =>
                {
                    // If there's an Authorization header, fall back to JWT
                    if (context.Request.Headers.ContainsKey("Authorization"))
                    {
                        return JwtBearerDefaults.AuthenticationScheme;
                    }
                    else
                    {
                        // Else, use cookie auth.
                        return OpenIdConnectDefaults.AuthenticationScheme;
                    }
                };
            })
            .AddJwtBearer(opt =>
            {
                opt.Audience = oneportalConfig.AADAuthAppId;
                opt.Authority = $"https://login.microsoftonline.com/{LibOnePortal.Secret.Constants.MsftTenentId}/v2.0";
                opt.SaveToken = true;
                opt.TokenValidationParameters = GetTokenValidationParameters(oneportalConfig);
            })
            .AddMicrosoftIdentityWebApp(options =>
            {
                options.ClientId = oneportalConfig.AADAuthAppId;
                options.TenantId = LibOnePortal.Secret.Constants.MsftTenentId;
                options.Instance = "https://login.microsoftonline.com/";
                options.CallbackPath = "/signin-oidc";
                options.SaveTokens = true;
            });

            // Please refer to https://github.com/AzureAD/microsoft-identity-web/issues/115,
            // it seems that this is a bug in azure container
            services.Configure<Microsoft.AspNetCore.Authentication.OpenIdConnect.OpenIdConnectOptions>(
                OpenIdConnectDefaults.AuthenticationScheme,
                options =>
                {
                    var redirectToIdpHandler = options.Events.OnRedirectToIdentityProvider;
                    options.Events.OnRedirectToIdentityProvider = async context =>
                    {
                        await redirectToIdpHandler(context);
                        context.ProtocolMessage.RedirectUri = ConstructRedirectUri(context.Request);

                        // context.ProtocolMessage.PostLogoutRedirectUri = "your post logout URI";
                    };
                });

            if (!webhostEnv.IsDevelopment() && !webhostEnv.IsTesting())
            {
                var pmeTokenCred = credentialFactory.CreateTokenCredential(ISExpAuthToolkit.AADTenant.PME);
                var msftTokenCred = credentialFactory.CreateTokenCredential();
                const string StorageAccountName = "bingoneportalstorage";

                // Use the new Azure SDK approach with BlobContainerClient
                var blobUri = new Uri($"https://{StorageAccountName}.blob.core.windows.net/bingoneportaldataprotection/oneportaltemplatekeys.xml");
                var keyUri = new Uri($"{LibOnePortal.Secret.Constants.KeyVaultURL}{LibOnePortal.Secret.Constants.ProtectionKeyURI}");

                // TO be done, move all to PME get rid of MSFT dependency.
                services.AddDataProtection()
                    .PersistKeysToAzureBlobStorage(blobUri, pmeTokenCred)
                    .ProtectKeysWithAzureKeyVault(keyUri, msftTokenCred);
            }
        }

        /// <summary>
        /// GetTokenValidationParameters.
        /// </summary>
        /// <param name="config">config.</param>
        /// <returns>token parameters.</returns>
        private static TokenValidationParameters GetTokenValidationParameters(OnePortalConfig config)
        {
            if (config.EnablePmeAndMsftApiAccess)
            {
                return new TokenValidationParameters
                {
                    ValidAudiences = [config.AADAuthAppId, $"api://{config.AADAuthAppId}"],
                    ValidIssuers = [$"https://sts.windows.net/{ISExpAuthToolkit.Constants.MsftTenantId}/", $"https://sts.windows.net/{ISExpAuthToolkit.Constants.PmeTenantId}/"],
                };
            }
            else
            {
                return new TokenValidationParameters();
            }
        }

        /// <summary>
        /// Constructs the redirect URI.
        /// </summary>
        /// <param name="request">The HTTP request.</param>
        /// <returns>The constructed redirect URI.</returns>
        private static string ConstructRedirectUri(HttpRequest request)
        {
            var sb = new StringBuilder();

            // In local box we use http, in real environments, we use https
            if (request.Host.Value.StartsWith("localhost", StringComparison.InvariantCultureIgnoreCase))
            {
                sb.Append("http://");
            }
            else
            {
                sb.Append("https://");
            }

            sb.Append(request.Host.Value);
            sb.Append("/signin-oidc");
            return sb.ToString();
        }
    }
}

