// Copyright (c) Microsoft. All rights reserved.
// </copyright>

namespace CodeXCore.ServiceTree
{
    using System;
    using System.Collections.Generic;
    using System.Text.Json;
    using System.Threading.Tasks;
    using GitClientInterface;
    using Microsoft.Extensions.Logging;

    /// <summary>
    /// Parent service group catalog that auto-refreshes from a Git repository.
    /// </summary>
    public sealed class ServiceTreeParentGroupCatalog : IServiceTreeParentGroupCatalog
    {
        private const string GitFileUrl = "https://msasg.visualstudio.com/Bing_and_IPG/_git/Oneportal?path=/fleetServices/CodexSite/src/Core/ServiceTree/Data/ServiceTreeParentGroups.json";

        private static readonly JsonSerializerOptions JsonOptions = new JsonSerializerOptions
        {
            PropertyNameCaseInsensitive = true,
        };

        private readonly IGitClient gitClient;
        private readonly ILogger<ServiceTreeParentGroupCatalog> logger;

        private volatile CachedCatalog cached;

        /// <summary>
        /// Initializes a new instance of the <see cref="ServiceTreeParentGroupCatalog"/> class.
        /// </summary>
        /// <param name="gitClient">Git client for downloading files from ADO.</param>
        /// <param name="logger">Logger instance.</param>
        public ServiceTreeParentGroupCatalog(
            IGitClient gitClient,
            ILogger<ServiceTreeParentGroupCatalog> logger)
        {
            this.gitClient = gitClient ?? throw new ArgumentNullException(nameof(gitClient));
            this.logger = logger ?? throw new ArgumentNullException(nameof(logger));
        }

        /// <inheritdoc/>
        public async Task<ParentGroupCatalogSnapshot> GetSnapshotAsync()
        {
            var latestObjectId = await this.gitClient.GetFileObjectIdAsync(GitFileUrl);

            var current = this.cached;
            if (current != null && current.IsUpToDate(latestObjectId))
            {
                return current.Snapshot;
            }

            this.logger.LogInformation(
                "ServiceTreeParentGroupCatalog: Refreshing parent group catalog from Git: {Url} (objectId {ObjectId})",
                GitFileUrl,
                latestObjectId);

            var json = await this.gitClient.DownloadGitFileAsStringAsync(GitFileUrl);

            var parents = JsonSerializer.Deserialize<List<ParentServiceGroupInfo>>(json, JsonOptions)
                ?? new List<ParentServiceGroupInfo>();

            var snapshot = new ParentGroupCatalogSnapshot(parents);
            this.cached = new CachedCatalog(latestObjectId, snapshot);

            this.logger.LogInformation(
                "ServiceTreeParentGroupCatalog: Loaded {Count} parent groups (objectId {ObjectId}).",
                parents.Count,
                latestObjectId);

            return snapshot;
        }

        private sealed record CachedCatalog(string ObjectId, ParentGroupCatalogSnapshot Snapshot)
        {
            public bool IsUpToDate(string latestObjectId) =>
                latestObjectId != null && string.Equals(latestObjectId, this.ObjectId, StringComparison.OrdinalIgnoreCase);
        }
    }
}

