namespace CodeXCore.UtilizationMetricCollection
{
    using System;
    using System.Collections.Generic;
    using System.Linq;
    using System.Threading;
    using System.Threading.Tasks;
    using CodeXCore.Services;
    using CodeXCore.UtilizationMetricCollection.Transform;
    using CodeXEntities;
    using GitClientInterface;
    using Microsoft.Extensions.Logging;
    using Papyrus.SDK;

    /// <summary>
    /// Scoped service that performs a single utilization metric collection cycle.
    /// All dependencies are constructor-injected for testability.
    /// </summary>
    public sealed class UtilizationMetricCollector
    {
        private readonly IUnitOfCodeX unitOfCodeX;
        private readonly IPapyrusModelUtilizationService utilizationService;
        private readonly IGitClient gitClient;
        private readonly PapyrusEnvironmentProperties papyrusEnvProps;
        private readonly IMetricsTableBuilder<GpuUtilizationByModelOrgRow> gpuUtilizationByModelOrgBuilder;
        private readonly IMetricsTableBuilder<GpuUtilizationByAppIdRow> gpuUtilizationByAppIdBuilder;
        private readonly GpuUtilizationByRootAppIdBuilder gpuUtilizationByRootAppIdBuilder;
        private readonly IMetricsTableBuilder<GpuAllocationByModelRegionRow> gpuAllocationByModelRegionBuilder;
        private readonly IMetricsTableBuilder<GlobalGpuAvailabilityRow> globalGpuAvailabilityBuilder;
        private readonly IMetricsTableBuilder<RegionalGpuAvailabilityRow> regionalGpuAvailabilityBuilder;
        private readonly IMetricsTableBuilder<SubscriptionGpuAvailabilityRow> subscriptionGpuAvailabilityBuilder;
        private readonly IAppIdToProductResolver appIdToProductResolver;
        private readonly ILogger<UtilizationMetricCollector> logger;

        /// <summary>
        /// Initializes a new instance of the <see cref="UtilizationMetricCollector"/> class.
        /// </summary>
        /// <param name="unitOfCodeX">The CodeX unit of work for database access.</param>
        /// <param name="utilizationService">The Papyrus utilization data service.</param>
        /// <param name="gitClient">The Git client for fetching Papyrus config.</param>
        /// <param name="papyrusEnvProps">Papyrus environment properties.</param>
        /// <param name="gpuUtilizationByModelOrgBuilder">Builder for Table 1 (GPU utilization by model org).</param>
        /// <param name="gpuUtilizationByAppIdBuilder">Builder for Table 2 (GPU utilization by AppId).</param>
        /// <param name="gpuUtilizationByRootAppIdBuilder">Builder for Table 2b (GPU utilization by root AppId).</param>
        /// <param name="gpuAllocationByModelRegionBuilder">Builder for Table 3 (GPU allocation by model region).</param>
