// --------------------------------------------------------------------
// <copyright file="UtilizationMetricBackgroundService.cs" company="Microsoft">
//   Copyright (c) Microsoft. All rights reserved.
// </copyright>
// --------------------------------------------------------------------

namespace CodeXCore.UtilizationMetricCollection
{
    using System;
    using System.Threading;
    using System.Threading.Tasks;
    using CodeXCore.UtilizationMetricCollection.Counter;
    using Microsoft.Extensions.DependencyInjection;
    using Microsoft.Extensions.Hosting;
    using Microsoft.Extensions.Logging;

    /// <summary>
    /// Singleton background service that periodically delegates to a scoped
    /// <see cref="UtilizationMetricCollector"/> instance to fetch utilization data,
    /// build metrics tables, and emit MDM counters.
    /// </summary>
    public sealed class UtilizationMetricBackgroundService : BackgroundService
    {
        private const int SleepIntervalInMs = 1000 * 60 * 15; // 15 min

        private readonly IServiceProvider serviceProvider;
        private readonly ILogger<UtilizationMetricBackgroundService> logger;
        private readonly IUtilizationCounterManager counterManager;

        private volatile UtilizationMetricCollectionResult lastResult = new();

        /// <summary>
        /// Initializes a new instance of the <see cref="UtilizationMetricBackgroundService"/> class.
        /// </summary>
        /// <param name="serviceProvider">The service provider.</param>
        /// <param name="logger">The logger.</param>
        /// <param name="counterManager">The utilization counter manager.</param>
        public UtilizationMetricBackgroundService(
            IServiceProvider serviceProvider,
            ILogger<UtilizationMetricBackgroundService> logger,
            IUtilizationCounterManager counterManager)
        {
            this.serviceProvider = serviceProvider ?? throw new ArgumentNullException(nameof(serviceProvider));
            this.logger = logger ?? throw new ArgumentNullException(nameof(logger));
            this.counterManager = counterManager ?? throw new ArgumentNullException(nameof(counterManager));
        }

        /// <inheritdoc/>
        protected override async Task ExecuteAsync(CancellationToken stoppingToken)
        {
            this.logger.LogInformation("UtilizationMetricBackgroundService started.");

            while (!stoppingToken.IsCancellationRequested)
            {
                try
                {
                    using var scope = this.serviceProvider.CreateScope();
                    var collector = scope.ServiceProvider.GetRequiredService<UtilizationMetricCollector>();
                    this.lastResult = await collector.CollectAsync(stoppingToken);
                    this.counterManager.EmitAll(this.lastResult);
                    this.logger.LogInformation("UtilizationMetricBackgroundService emitted MDM counters for all tables.");
                }
                catch (Exception ex)
                {
                    this.logger.LogError(ex, "Error in UtilizationMetricBackgroundService.");
                    throw;
                }

                try
                {
                    await Task.Delay(SleepIntervalInMs, stoppingToken);
                }
                catch (TaskCanceledException)
                {
                    break;
                }
            }

            this.logger.LogInformation("UtilizationMetricBackgroundService stopped.");
        }
    }
}

