namespace Microsoft.Falcon.CodexUpdater
{
    using System.Threading.Tasks;
    using Microsoft.AspNetCore;
    using Microsoft.AspNetCore.Hosting;
    using Microsoft.Extensions.DependencyInjection;
    using Microsoft.Extensions.Hosting;
    using Microsoft.Extensions.Logging;

    /// <summary>
    /// The program class containing the entry point of the application.
    /// </summary>
    public static class Program
    {
        /// <summary>
        /// The main method, entry point of the application.
        /// </summary>
        /// <param name="args">The program arguments.</param>
        /// <returns>A task that represents the asynchronous operation.</returns>
        public static Task Main(string[] args)
        {
            var builder = WebHost.CreateDefaultBuilder(args)
                .UseStartup<Startup>()
                .UseUrls($"http://*:{GetContainerPort()}")
                .UseShutdownTimeout(System.TimeSpan.FromMinutes(5));

            builder.ConfigureLogging(logging =>
            {
                logging.ClearProviders();
                logging.AddConsole();
                logging.SetMinimumLevel(LogLevel.Information);
            });

            builder.ConfigureServices(services =>
                services.AddHostedService<CodexUpdaterService>());
            var host = builder.Build();
            return host.RunAsync();
        }

        /// <summary>
        /// Retrieves the container port from the environment variables.
        /// </summary>
        /// <returns>The container port as an integer. Defaults to 5004 if not set or invalid.</returns>
        private static int GetContainerPort()
        {
            const int DefaultPort = 5004;
            var port = System.Environment.GetEnvironmentVariable("HOSTING__PORT");

            if (!string.IsNullOrEmpty(port) && int.TryParse(port, out int result))
            {
                return result;
            }

            return DefaultPort;
        }
    }
}

