public void ConfigureServices(IServiceCollection services)
{
    services.AddOnePortalFalconBackendServices("CodexUpdater");
    services.AddSingleton<IArmClientWrapper, ArmClientAPIProxyWrapper>();
    services.AddSingleton<IArmRestApiWrapper, ArmRestClientAPIProxyWrapper>();
    services.AddSingleton<ISecretStore, GalaxyVaultSecretStore>();

    services.AddSingleton<DBConnectionProperties>();
    services.AddScoped<IUnitOfCodeX, UnitOfCodeX>();
    services.AddSingleton<IAOAIClient, AOAIClient>();
    services.AddSingleton<IOCIRestApiClient>(sp => new OCIRestApiClient(new BasicTokenCredAuthProvider(sp.GetService<ICredentialFactory>().CreateTokenCredential(AADTenant.PME))));
    services.AddSingleton<IEnvironmentProperties, EnvironmentProperties>();
    services.AddSingleton<IPapyrusClient, PapyrusClient>();
    services.AddScoped<EndpointUpdater>();
    services.AddScoped<MssAndMpcpUpdater>();
    services.AddScoped<ICodeXService, CodeXService>();
    services.AddScoped<ISKUService, SKUService>();
    services.AddSingleton<AdoCredentialFactory>();
    services.AddSingleton<IGitClient>(sp => new GitClient(new TokenProviderDelegatingHandler(new AzureCredentialTokenProvider(new[] { ISExpAuthToolkit.Constants.AzureADDevOpsScope }, sp.GetService<AdoCredentialFactory>().GetPrimaryAdoCredential()))));
    services.AddSingleton<CodexCore.Services.ICapacityCounterMetricsCounters, CodexImplementation.CapacityCounterMetricsCounters>();
    services.AddMdmLogging(options =>
    {
        options.AddCounterRule(
            "Microsoft.Falcon.CodexSite",
            "BingIndexServeGalaxy",
            "CodexCapacity");
    });

    services.AddSingleton<PapyrusEnvironmentProperties>(sp => EnvUtil.ResolvePapyrusEnvProperties(sp.GetService<IEnvironmentProperties>()));
    services.AddSingleton<IPullRequestClient>(sp =>
    {
        var papyrusEnvProps = sp.GetService<PapyrusEnvironmentProperties>();
        var adoCredFactory = sp.GetService<AdoCredentialFactory>();
        return new PullRequestClient(
            papyrusEnvProps.AdoOrg,
            papyrusEnvProps.AdoProject,
            papyrusEnvProps.AdoRep,
            adoCredFactory.GetPrimaryAdoCredential(),
            prApprovalCredential: adoCredFactory.GetSecondaryAdoCredential());
    });
    services.AddScoped<IPapyrusConfigService, PapyrusConfigService>();
    services.AddSingleton<CodeXCore.UtilizationMetricCollection.Transform.IMetricsTableBuilder<CodeXCore.UtilizationMetricCollection.Transform.GpuUtilizationByModelOrgRow>, CodeXCore.UtilizationMetricCollection.Transform.GpuUtilizationByModelOrgBuilder>();
    services.AddSingleton<CodeXCore.UtilizationMetricCollection.Transform.IMetricsTableBuilder<CodeXCore.UtilizationMetricCollection.Transform.GpuUtilizationByAppIdRow>, CodeXCore.UtilizationMetricCollection.Transform.GpuUtilizationByAppIdBuilder>();
    services.AddSingleton<CodeXCore.UtilizationMetricCollection.Transform.GpuUtilizationByRootAppIdBuilder>();
    services.AddSingleton<CodeXCore.UtilizationMetricCollection.Transform.IMetricsTableBuilder<CodeXCore.UtilizationMetricCollection.Transform.GpuAllocationByModelRegionRow>, CodeXCore.UtilizationMetricCollection.Transform.GpuAllocationByModelRegionBuilder>();
    services.AddSingleton<CodeXCore.UtilizationMetricCollection.Transform.IMetricsTableBuilder<CodeXCore.UtilizationMetricCollection.Transform.GlobalGpuAvailabilityRow>, CodeXCore.UtilizationMetricCollection.Transform.GlobalGpuAvailabilityBuilder>();
    services.AddSingleton<CodeXCore.UtilizationMetricCollection.Transform.IMetricsTableBuilder<CodeXCore.UtilizationMetricCollection.Transform.RegionalGpuAvailabilityRow>, CodeXCore.UtilizationMetricCollection.Transform.RegionalGpuAvailabilityBuilder>();
    services.AddSingleton<CodeXCore.UtilizationMetricCollection.Transform.IMetricsTableBuilder<CodeXCore.UtilizationMetricCollection.Transform.SubscriptionGpuAvailabilityRow>, CodeXCore.UtilizationMetricCollection.Transform.SubscriptionGpuAvailabilityBuilder>();
    services.AddScoped<CodeXCore.UtilizationMetricCollection.UtilizationMetricCollector>();
    services.AddHostedService<CodeXCore.UtilizationMetricCollection.UtilizationMetricBackgroundService>();

    // Papyrus metrics: MDM-based implementation (replaces Kusto-based PapyrusWeeklyUtilizationService).
    services.AddSingleton(sp =>
    {
        var config = sp.GetRequiredService<Microsoft.Extensions.Configuration.IConfiguration>();
        return new PapyrusMdmOptions
        {
            Account = config["PapyrusMdm:Account"]
                ?? Environment.GetEnvironmentVariable("PAPYRUS_MDM_ACCOUNT")
                ?? "PapyrusTelemetry",
            Namespace = config["PapyrusMdm:Namespace"]
                ?? Environment.GetEnvironmentVariable("PAPYRUS_MDM_NAMESPACE")
                ?? "Papyrus",
        };
    });
    services.AddSingleton<IKeyVaultCertProvider, KeyVaultCertProvider>();
    services.AddSingleton<IPapyrusModelUtilizationService, PapyrusModelUtilizationMdmService>();
    services.AddSingleton<CodeXCore.UtilizationMetricCollection.Counter.IUtilizationCounterManager, CodeXCore.UtilizationMetricCollection.Counter.CompositeUtilizationCounterManager>();
    services.AddSingleton(ServiceTreeKustoOptions.FromEnvironment());
    services.AddSingleton<IServiceTreeNodeLookup, ServiceTreeKustoClient>();
    services.AddSingleton<IServiceTreeParentGroupCatalog, ServiceTreeParentGroupCatalog>();
    services.AddScoped<IServiceTreeParentResolver, ServiceTreeParentResolver>();
    services.AddScoped<IAppIdToProductResolver, AppIdToProductResolver>();
}
